using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ApiTools
{
    [McpServerTool, Description("Fetches data from an external API for the given resource path.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        [Description("The API resource path to fetch (e.g. \"/users/1\").")] string path,
        CancellationToken cancellationToken)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Generates a prompt that asks the model to summarize the provided text.")]
    public static ChatMessage[] Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional maximum length hint (e.g. \"2 sentences\").")] string? maxLength = null)
    {
        var instruction = maxLength is not null
            ? $"Summarize the following text in {maxLength}."
            : "Summarize the following text concisely.";

        return
        [
            new(Role.User, $"{instruction}\n\n{text}")
        ];
    }
}

