using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Generates a prompt that asks the model to summarize the provided text.")]
    public static ChatMessage[] Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional maximum length hint (e.g. \"2 sentences\").")] string? maxLength = null)
    {
        var instruction = maxLength is not null
